def main():
    existing = load_synthesis('hebrews')
    merge_synthesis(existing, HEBREWS)
    save_synthesis('hebrews', existing)

    # Verify all 25 verses present
    import json as _json, pathlib as _pl
    il = _json.loads((_pl.Path(__file__).parent.parent / 'data/interlinear/hebrews.json').read_text())
    syn_path = _pl.Path(__file__).parent.parent / 'data/commentary/synthesis/hebrews.json'
    syn = _json.loads(syn_path.read_text()) if syn_path.exists() else {}
    il_vv = set(il.get('13', {}).keys())
    syn_vv = set(syn.get('13', {}).keys())
    missing = il_vv - syn_vv
    if missing:
        print(f'WARNING: missing verses in ch 13: {sorted(missing, key=int)}')
    else:
        print(f'Hebrews 13 synthesis complete — all {len(syn_vv)} verses present.')

if __name__ == '__main__':
    main()
